=You are a project management analytics assistant.

Generate a concise, professional task summary using ONLY the data provided from ClickUp.  
Do not invent data or make assumptions. Base all calculations strictly on the task data.

Task Data:
Task ID: {{$json.id}}
Name: {{$json.name}}
Description: {{$json.description}}
Status: {{$json.status.status}}
Priority: {{ $json.priority }}
Assignees: {{$json.assignees.map(a => a.username).join(', ')}}
Creator: {{$json.creator.username}}
Due Date: {{$json.due_date}}
Date Created: {{$json.date_created}}
Date Updated: {{$json.date_updated}}
URL: {{$json.url}}
Project: {{$json.project.name}}
List: {{$json.list.name}}
Folder: {{$json.folder.name}}
Space ID: {{$json.space.id}}

Metrics (calculate based on task status and priority):
- Completed: {{$json.status.status === 'done' ? 1 : 0}}
- In Progress: {{$json.status.status === 'in progress' ? 1 : 0}}
- Pending: {{$json.status.status === 'to do' || $json.status.status === 'pending' ? 1 : 0}}
- Overdue: {{($json.due_date && Number($json.due_date) < Date.now() && $json.status.status !== 'done') ? 1 : 0}}
- Productivity: {{($json.status.status === 'done' ? 100 : 0)}}%
- KPI Score: [calculate based on completed tasks, priority, and overdue metrics]
- Rating: [High priority & overdue → Critical, Medium priority → Needs Improvement, Low → Good]

Output plain text ONLY, in this format:

Task Summary
Task ID: <id>
Name: <name>
Project: <project>
Folder: <folder>
List: <list>
Space ID: <space_id>

Overview:
- Description: <description>
- Status: <status>
- Priority: <priority>
- Assignees: <assignees>
- Creator: <creator>
- Dates:
    • Due: <due_date>
    • Created: <date_created>
    • Updated: <date_updated>

Metrics:
- Completed: <number>
- In Progress: <number>
- Pending: <number>
- Overdue: <number>
- Productivity: <percentage>%
- KPI Score: <score>
- Rating: <rating>

Task Link: <url>

Insight:
Provide a one-line performance summary of this task's status and priority, explaining the current KPI score, rating, and any action required.

parameters.jsCode:
// Get all items from previous node
const items = $input.all();

// Helper function to calculate KPI score
function calculateKPI(task) {
    // Base KPI: 100 if done, 50 if in progress, 0 if pending
    let base = 0;
    if (task.overview.status.toLowerCase() === 'done') base = 100;
    else if (task.overview.status.toLowerCase() === 'in progress') base = 60;
    else base = 30;

    // Adjust based on priority
    const priority = task.overview.priority.toLowerCase();
    if (priority === 'high') base += 10;
    else if (priority === 'low') base -= 10;

    // Reduce if overdue
    if (task.metrics.overdue > 0) base -= 20;

    // Clamp 0-100
    return Math.max(0, Math.min(100, base));
}

// Helper to get Rating based on KPI Score
function calculateRating(kpiScore) {
    if (kpiScore >= 80) return 'Excellent';
    if (kpiScore >= 60) return 'Needs Improvement';
    if (kpiScore >= 40) return 'Average';
    return 'Poor';
}

// Initialize result array
const parsedTasks = [];

items.forEach(item => {
    // Safely access the ChatGPT text
    const content = item.json.output?.[0]?.content?.[0]?.text;
    if (!content) return; // skip if no text

    const lines = content.split('\n').map(l => l.trim()).filter(l => l);

    // Initialize task object
    let taskData = {
        taskSummary: '',
        taskId: '',
        name: '',
        project: '',
        folder: '',
        list: '',
        spaceId: '',
        overview: {
            description: '',
            status: '',
            priority: '',
            assignees: [],
            creator: '',
            dates: {
                due: null,
                created: null,
                updated: null
            }
        },
        metrics: {
            completed: 0,
            inProgress: 0,
            pending: 0,
            overdue: 0,
            productivity: '',
            kpiScore: 0,
            rating: '',
        },
        taskLink: '',
        insight: ''
    };

    let currentSection = '';

    function parseNumber(str) { const n = Number(str); return isNaN(n)?0:n; }

    // Parse each line
    lines.forEach(line => {
        if (line.startsWith('Task Summary')) taskData.taskSummary = 'Task Summary';
        else if (line.startsWith('Task ID:')) taskData.taskId = line.replace('Task ID:','').trim();
        else if (line.startsWith('Name:')) taskData.name = line.replace('Name:','').trim();
        else if (line.startsWith('Project:')) taskData.project = line.replace('Project:','').trim();
        else if (line.startsWith('Folder:')) taskData.folder = line.replace('Folder:','').trim();
        else if (line.startsWith('List:')) taskData.list = line.replace('List:','').trim();
        else if (line.startsWith('Space ID:')) taskData.spaceId = line.replace('Space ID:','').trim();
        else if (line.startsWith('Overview:')) currentSection = 'overview';
        else if (line.startsWith('Metrics:')) currentSection = 'metrics';
        else if (line.startsWith('Task Link:')) taskData.taskLink = line.replace('Task Link:','').trim();
        else if (line.startsWith('Insight:')) currentSection = 'insight';
        else {
            if (currentSection === 'overview') {
                if (line.startsWith('- Description:')) taskData.overview.description = line.replace('- Description:','').trim();
                else if (line.startsWith('- Status:')) taskData.overview.status = line.replace('- Status:','').trim();
                else if (line.startsWith('- Priority:')) taskData.overview.priority = line.replace('- Priority:','').trim();
                else if (line.startsWith('- Assignees:')) {
                    const assigneesText = line.replace('- Assignees:','').trim();
                    taskData.overview.assignees = assigneesText ? assigneesText.split(',').map(a=>a.trim()) : [];
                }
                else if (line.startsWith('- Creator:')) taskData.overview.creator = line.replace('- Creator:','').trim();
                else if (line.startsWith('• Due:')) taskData.overview.dates.due = line.replace('• Due:','').trim() || null;
                else if (line.startsWith('• Created:')) taskData.overview.dates.created = Number(line.replace('• Created:','').trim()) || null;
                else if (line.startsWith('• Updated:')) taskData.overview.dates.updated = Number(line.replace('• Updated:','').trim()) || null;
            } else if (currentSection === 'metrics') {
                if (line.startsWith('- Completed:')) taskData.metrics.completed = parseNumber(line.replace('- Completed:','').trim());
                else if (line.startsWith('- In Progress:')) taskData.metrics.inProgress = parseNumber(line.replace('- In Progress:','').trim());
                else if (line.startsWith('- Pending:')) taskData.metrics.pending = parseNumber(line.replace('- Pending:','').trim());
                else if (line.startsWith('- Overdue:')) taskData.metrics.overdue = parseNumber(line.replace('- Overdue:','').trim());
                else if (line.startsWith('- Productivity:')) taskData.metrics.productivity = line.replace('- Productivity:','').trim();
                // KPI and Rating will be recalculated
            } else if (currentSection === 'insight') {
                taskData.insight += (taskData.insight ? ' ' : '') + line;
            }
        }
    });

    // Calculate KPI Score and Rating based on parsed metrics
    taskData.metrics.kpiScore = calculateKPI(taskData);
    taskData.metrics.rating = calculateRating(taskData.metrics.kpiScore);

    // Optional: Generate summary insight automatically if not present
    if (!taskData.insight) {
        taskData.insight = `Task has status "${taskData.overview.status}" with priority "${taskData.overview.priority}" and KPI ${taskData.metrics.kpiScore}, rating ${taskData.metrics.rating}.`;
    }

    parsedTasks.push({ json: taskData });
});

return parsedTasks;
